+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+function getCwd(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  return Deno?.cwd() ?? process?.cwd() ?? ".";
+}
+
+function join(path: string, file: string): string {
+  return path.endsWith("/") || path.endsWith("\\\\")
+    ? `${path}${file}`
+    : `${path}/${file}`;
+}
+
+async function readTextFile(path: string): Promise<string | undefined> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    const { readFile } = await import("node:fs/promises");
+    return await readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" ||
+      error instanceof Deno?.errors?.NotFound) {
+      return undefined;
+    }
+    throw error;
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator < 1) throw new Error("Expected key=value pair.");
+    const key = trimmed.slice(0, separator).trim();
+    let value = trimmed.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error("Unterminated quoted value.");
+      }
+      value = value.slice(1, -1);
+    }
+    values[key] = value === "true" ? true : value === "false" ? false
+      : /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value) ? Number(value) : value;
+  }
+  return values;
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  return Object.entries(value).reduce((result, [key, child]) => {
+    const name = prefix ? `${prefix}.${key}` : key;
+    if (child && typeof child === "object" && !Array.isArray(child)) {
+      Object.assign(result, flatten(child as Record<string, unknown>, name));
+    } else result[name] = child;
+    return result;
+  }, {} as Record<string, unknown>);
+}
+
+function fileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const formats = options.formats ?? [".json", ".rc"];
+  const paths = options.searchPaths ?? [getCwd()];
+  let values: Record<string, unknown> = {};
+  let path: string | undefined;
+
+  for (const searchPath of paths) {
+    let found = false;
+    for (const format of formats) {
+      const candidate = join(searchPath, fileName(options.name, format));
+      const content = await readTextFile(candidate);
+      if (typeof content === "undefined") continue;
+      try {
+        const parsed = options.parser
+          ? options.parser(content)
+          : format === ".rc" ? parseRc(content) : JSON.parse(content);
+        if (!parsed || Array.isArray(parsed) || typeof parsed !== "object") {
+          throw new Error("Configuration must be an object.");
+        }
+        const config = flatten(parsed);
+        path ??= candidate;
+        values = options.mergeConfigs ? { ...config, ...values } : config;
+        found = true;
+        break;
+      } catch (error) {
+        throw new ConfigParseError(candidate, error);
+      }
+    }
+    if (found && !options.mergeConfigs) break;
+  }
+  return { path, values };
+}
